@Component({
  selector: 'hb-menu-checkbox-item',
  imports: [NgIcon],
  hostDirectives: [CdkMenuItemCheckbox],
  viewProviders: [provideIcons({ phosphorCheck })],
  template: `
    <span [class]="indicatorClasses">
      @if (hbChecked()) {
        <ng-icon name="phosphorCheck" />
